+  if (!commitSha) {
+    // Has our link but no commit SHA - commit might have failed
+    logger.debug("OpenCode PostToolUse: found link but no commit SHA", {
+      sessionId: sessionId.substring(0, 8),
+      transcriptId,
+      fromCache,
+    });
+    return;
+  }
+
+  await trackCommit({
+    transcriptId,
+    repoPath: cwd,
+    timestamp: new Date().toISOString(),
+    commitSha,
+    commitTitle,
+    branch,
+  });
